import React, { useState } from "react";

const Chatbot = () => {

const [open,setOpen] = useState(false);
const [messages,setMessages] = useState([
{ text:"Hello 👋 Welcome to Sun Emirates. How can I help you?", bot:true }
]);

const [input,setInput] = useState("");

const sendMessage = () => {

if(!input.trim()) return;

const userMsg = { text:input, bot:false };

let reply = "Please contact our team at sales@sunemirates.com";

const text = input.toLowerCase();

if(text.includes("services")){
reply="We provide stainless steel works, mild steel fabrication, machine shop and finishing services.";
}

if(text.includes("contact")){
reply="Phone: +971-6-7481646 Email: sales@sunemirates.com";
}

if(text.includes("location")){
reply="We are located in Ajman Industrial Area, UAE.";
}

setMessages([...messages,userMsg,{text:reply,bot:true}]);

setInput("");

};

return(

<div>

{/* Chat Window */}

{open && (

<div style={styles.chatContainer}>

<div style={styles.header}>
Sun Emirates Chat
</div>

<div style={styles.chatBody}>

{messages.map((msg,i)=>(
<div
key={i}
style={{
...styles.message,
alignSelf: msg.bot ? "flex-start":"flex-end",
background: msg.bot ? "#eee":"#342a67",
color: msg.bot ? "#000":"#fff"
}}
>
{msg.text}
</div>
))}

</div>

<div style={styles.inputArea}>

<input
type="text"
value={input}
onChange={(e)=>setInput(e.target.value)}
placeholder="Type message..."
style={styles.input}
/>

<button onClick={sendMessage} style={styles.button}>
Send
</button>

</div>

</div>

)}

{/* Chat Icon */}

<div style={styles.chatIcon} onClick={()=>setOpen(!open)}>

<img
src="/images/chatbot.png"
alt="chat"
style={{width:"60px"}}
/>

</div>

</div>

);

};

const styles = {

chatIcon:{
position:"fixed",
bottom:"20px",
right:"20px",
cursor:"pointer",
zIndex:1000
},

chatContainer:{
position:"fixed",
bottom:"90px",
right:"20px",
width:"320px",
background:"#fff",
borderRadius:"10px",
boxShadow:"0 0 10px rgba(0,0,0,0.3)",
display:"flex",
flexDirection:"column",
overflow:"hidden",
zIndex:1000
},

header:{
background:"#342a67",
color:"#fff",
padding:"10px",
fontWeight:"bold"
},

chatBody:{
height:"300px",
overflowY:"auto",
display:"flex",
flexDirection:"column",
padding:"10px",
gap:"8px"
},

message:{
padding:"8px 10px",
borderRadius:"8px",
maxWidth:"75%"
},

inputArea:{
display:"flex",
borderTop:"1px solid #ccc"
},

input:{
flex:1,
padding:"8px",
border:"none",
outline:"none"
},

button:{
background:"#342a67",
color:"#fff",
border:"none",
padding:"8px 12px",
cursor:"pointer"
}

};

export default Chatbot;
